// API utility functions for frontend
const API_BASE = "/api";
// Generic fetch wrapper
async function fetchApi(endpoint, options) {
    try {
        const res = await fetch(`${API_BASE}${endpoint}`, {
            headers: {
                "Content-Type": "application/json",
                ...options?.headers
            },
            ...options
        });
        const data = await res.json();
        if (!res.ok) {
            return {
                success: false,
                error: data.error || data.message || "Request failed"
            };
        }
        return {
            success: true,
            data
        };
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : "Network error"
        };
    }
}
async function loginUser(credentials) {
    return fetchApi("/auth/login", {
        method: "POST",
        body: JSON.stringify(credentials)
    });
}
async function getTokens(params) {
    const searchParams = new URLSearchParams();
    if (params?.busunitid) searchParams.set("busunitid", String(params.busunitid));
    if (params?.status) searchParams.set("status", params.status);
    if (params?.date) searchParams.set("date", params.date);
    const query = searchParams.toString();
    return fetchApi(`/tokens${query ? `?${query}` : ""}`);
}
async function createToken(token) {
    return fetchApi("/tokens", {
        method: "POST",
        body: JSON.stringify(token)
    });
}
async function updateTokenStatus(tokenid, status) {
    return fetchApi("/tokens", {
        method: "PUT",
        body: JSON.stringify({
            tokenid,
            tokenstatus: status
        })
    });
}
async function getApplicants(params) {
    const searchParams = new URLSearchParams();
    if (params?.busunitid) searchParams.set("busunitid", String(params.busunitid));
    if (params?.cnic) searchParams.set("cnic", params.cnic);
    if (params?.search) searchParams.set("search", params.search);
    const query = searchParams.toString();
    return fetchApi(`/applicants${query ? `?${query}` : ""}`);
}
async function getApplicantByCnic(cnic) {
    return fetchApi(`/applicants?cnic=${encodeURIComponent(cnic)}`);
}
async function createApplicant(applicant) {
    return fetchApi("/applicants", {
        method: "POST",
        body: JSON.stringify(applicant)
    });
}
async function updateApplicant(applicant) {
    return fetchApi("/applicants", {
        method: "PUT",
        body: JSON.stringify(applicant)
    });
}
async function getLicenseTypes() {
    return fetchApi("/license-types");
}
async function getLicenseCategories(licensetypeid) {
    const query = licensetypeid ? `?licensetypeid=${licensetypeid}` : "";
    return fetchApi(`/license-types/categories${query}`);
}
async function getLookups(type) {
    return fetchApi(`/lookups?type=${encodeURIComponent(type)}`);
}
async function testDatabaseConnection() {
    return fetchApi("/db-test");
}
